function selected_proposals_final_tdp_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('selected_proposals_final_tdp');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'project_id' => Request::lookup('project_id', ''),
		'breakthrough' => Request::val('breakthrough', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'short_name' => Request::val('short_name', ''),
		'duration_in_months' => Request::val('duration_in_months', ''),
		'name_of_pi' => Request::val('name_of_pi', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'institute' => Request::val('institute', ''),
		'stage_1' => Request::val('stage_1', ''),
		'stage_2' => Request::val('stage_2', ''),
		'stage_3' => Request::val('stage_3', ''),
		'stage_4' => Request::val('stage_4', ''),
		'total_budget_specified' => Request::val('total_budget_specified', ''),
		'one_slide_ppt_link' => Request::val('one_slide_ppt_link', ''),
		'proposal_link' => Request::val('proposal_link', ''),
		'existing_trl' => Request::val('existing_trl', ''),
		'expected_trl' => Request::val('expected_trl', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('selected_proposals_final_tdp', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		selected_proposals_final_tdp_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

