function selected_proposals_final_tdp_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('selected_proposals_final_tdp', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: selected_proposals_final_tdp_before_delete
	if(function_exists('selected_proposals_final_tdp_before_delete')) {
		$args = [];
		if(!selected_proposals_final_tdp_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `selected_proposals_final_tdp` WHERE `selected_proposals_id`='{$selected_id}'", $eo);

	// hook: selected_proposals_final_tdp_after_delete
	if(function_exists('selected_proposals_final_tdp_after_delete')) {
		$args = [];
		selected_proposals_final_tdp_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='selected_proposals_final_tdp' AND `pkValue`='{$selected_id}'", $eo);
}

function selected_proposals_final_tdp_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('selected_proposals_final_tdp', $selected_id, 'edit')) return false;

	$data = [
		'project_id' => Request::lookup('project_id', ''),
		'breakthrough' => Request::val('breakthrough', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'short_name' => Request::val('short_name', ''),
		'duration_in_months' => Request::val('duration_in_months', ''),
		'name_of_pi' => Request::val('name_of_pi', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'institute' => Request::val('institute', ''),
		'stage_1' => Request::val('stage_1', ''),
		'stage_2' => Request::val('stage_2', ''),
		'stage_3' => Request::val('stage_3', ''),
		'stage_4' => Request::val('stage_4', ''),
		'total_budget_specified' => Request::val('total_budget_specified', ''),
		'one_slide_ppt_link' => Request::val('one_slide_ppt_link', ''),
		'proposal_link' => Request::val('proposal_link', ''),
		'existing_trl' => Request::val('existing_trl', ''),
		'expected_trl' => Request::val('expected_trl', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('selected_proposals_final_tdp', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: selected_proposals_final_tdp_before_update
	if(function_exists('selected_proposals_final_tdp_before_update')) {
		$args = ['old_data' => $old_data];
		if(!selected_proposals_final_tdp_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'selected_proposals_final_tdp',
		backtick_keys_once($set),
		['`selected_proposals_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="selected_proposals_final_tdp_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('selected_proposals_final_tdp', $data['selectedID'], calculated_fields()['selected_proposals_final_tdp']);

	// hook: selected_proposals_final_tdp_after_update
	if(function_exists('selected_proposals_final_tdp_after_update')) {
		if($row = getRecord('selected_proposals_final_tdp', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['selected_proposals_id'];
		$args = ['old_data' => $old_data];
		if(!selected_proposals_final_tdp_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('selected_proposals_final_tdp', $selected_id);
}

